#include "vanilla_rnn_hidden_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    VanillaRnnHiddenCustomTilingData tiling;

    // Shapes:
    // x: [T, B, I]
    // h0: [B, H]
    // w_i2h: [H, K] where K = I + H
    // b_i2h: [H]
    // w_h2o: [O, H]
    // b_h2o: [O]
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *h0_shape = context->GetInputShape(1);
    const gert::Shape *w_i2h_shape = context->GetInputShape(2);
    const gert::Shape *b_i2h_shape = context->GetInputShape(3);
    const gert::Shape *w_h2o_shape = context->GetInputShape(4);
    const gert::Shape *b_h2o_shape = context->GetInputShape(5);

    if (x_shape->GetOriginShape().GetDimNum() != 3 ||
        h0_shape->GetOriginShape().GetDimNum() != 2 ||
        w_i2h_shape->GetOriginShape().GetDimNum() != 2 ||
        w_h2o_shape->GetOriginShape().GetDimNum() != 2) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t T = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    const uint32_t B = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    const uint32_t I = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2));
    const uint32_t H = static_cast<uint32_t>(h0_shape->GetOriginShape().GetDim(1));
    const uint32_t O = static_cast<uint32_t>(w_h2o_shape->GetOriginShape().GetDim(0));
    const uint32_t K = static_cast<uint32_t>(w_i2h_shape->GetOriginShape().GetDim(1));

    // Basic validations
    if (K != I + H) {
        return ge::GRAPH_FAILED;
    }

    uint32_t blockDim = B;
    if (blockDim < 1u) blockDim = 1u;
    if (blockDim > 32u) blockDim = 32u;
    context->SetBlockDim(blockDim);

    tiling.set_T(T);
    tiling.set_B(B);
    tiling.set_I(I);
    tiling.set_H(H);
    tiling.set_O(O);
    tiling.set_K(K);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    // Output y: [T,B,O]
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_h2o_shape = context->GetInputShape(4);
    if (x_shape->GetOriginShape().GetDimNum() != 3 ||
        w_h2o_shape->GetOriginShape().GetDimNum() != 2) {
        return GRAPH_FAILED;
    }
    const int64_t T = x_shape->GetOriginShape().GetDim(0);
    const int64_t B = x_shape->GetOriginShape().GetDim(1);
    const int64_t O = w_h2o_shape->GetOriginShape().GetDim(0);
    gert::Shape *y_shape = context->GetOutputShape(0);
    y_shape->SetDimNum(3);
    y_shape->SetDim(0, T);
    y_shape->SetDim(1, B);
    y_shape->SetDim(2, O);
    return GRAPH_SUCCESS;
}

